// src/components/MapComponent.js
import React, { useMemo, useRef, useCallback } from "react";
import { GoogleMap, Marker, useJsApiLoader } from "@react-google-maps/api";

// Helper to normalize different vehicle coordinate shapes
function getPosition(v) {
  // { lat, lng }
  if (typeof v?.lat === "number" && typeof v?.lng === "number") {
    return { lat: v.lat, lng: v.lng };
  }
  // { latitude, longitude }
  if (typeof v?.latitude === "number" && typeof v?.longitude === "number") {
    return { lat: v.latitude, lng: v.longitude };
  }
  // coords: [lat, lng]
  if (Array.isArray(v?.coords) && v.coords.length === 2) {
    const [lat, lng] = v.coords;
    if (typeof lat === "number" && typeof lng === "number") {
      return { lat, lng };
    }
  }
  // location: "lat,lng"
  if (typeof v?.location === "string") {
    const parts = v.location.split(",").map((s) => parseFloat(s.trim()));
    if (parts.length === 2 && parts.every((n) => !Number.isNaN(n))) {
      return { lat: parts, lng: parts[4] };
    }
  }
  return null;
}

export default function MapComponent({ vehicles = [] }) {
  const { isLoaded } = useJsApiLoader({
    id: "google-map-script",
    googleMapsApiKey: process.env.REACT_APP_GOOGLE_MAPS_API_KEY || "",
  });

  // Default center (Bengaluru) for first paint
  const defaultCenter = useMemo(() => ({ lat: 12.9716, lng: 77.5946 }), []);

  // Normalize positions once per render
  const positions = useMemo(
    () => vehicles.map(getPosition).filter(Boolean),
    [vehicles]
  );

  // Derive a center (average) if we have markers
  const derivedCenter = useMemo(() => {
    if (!positions.length) return defaultCenter;
    const sum = positions.reduce(
      (acc, p) => ({ lat: acc.lat + p.lat, lng: acc.lng + p.lng }),
      { lat: 0, lng: 0 }
    );
    return { lat: sum.lat / positions.length, lng: sum.lng / positions.length };
  }, [positions, defaultCenter]);

  const mapRef = useRef(null);
  const onLoad = useCallback((map) => {
    mapRef.current = map;
    // Fit bounds to markers if any exist
    if (positions.length) {
      const bounds = new window.google.maps.LatLngBounds();
      positions.forEach((p) => bounds.extend(p));
      map.fitBounds(bounds, 40); // 40px padding
    }
  }, [positions]);

  const onUnmount = useCallback(() => {
    mapRef.current = null;
  }, []);

  if (!isLoaded) return <div>Loading map…</div>;

  return (
    <GoogleMap
      onLoad={onLoad}
      onUnmount={onUnmount}
      center={derivedCenter}
      zoom={positions.length ? 12 : 11}
      mapContainerStyle={{ width: "100%", height: 360 }}
      options={{
        streetViewControl: false,
        mapTypeControl: false,
        fullscreenControl: false,
      }}
    >
      {positions.map((pos, i) => (
        <Marker
          key={vehicles[i]?.id ?? i}
          position={pos}
          title={`${vehicles[i]?.license_plate ?? vehicles[i]?.licensePlate ?? "Vehicle"} — ${vehicles[i]?.status ?? ""}`}
        />
      ))}
    </GoogleMap>
  );
}
